      const { db } = await import('../../server/db');
      const mockDbSelect = db.select as jest.MockedFunction<any>;
      mockDbSelect.mockReturnValue({
        from: jest.fn().mockReturnValue({
          innerJoin: jest.fn().mockReturnValue({
            innerJoin: jest.fn().mockReturnValue({
              orderBy: jest.fn().mockResolvedValue(testMeetings.map(meeting => ({
                ...meeting,
                organization: { id: testOrgs[0].id, name: testOrgs[0].name },
                creator: { 
                  id: testUsers[1].id, 
                  firstName: testUsers[1].firstName,
                  lastName: testUsers[1].lastName,
                  email: testUsers[1].email,
                },
              }))),
            }),
          }),
        }),
      });

      const response = await request(app)
        .get('/api/communication/meetings')
