  // ==========================================
  // RBAC COMPREHENSIVE TESTS
  // ==========================================

  describe('RBAC Enforcement', () => {
    const testEndpoints = [
      { method: 'get', path: '/api/communication/preferences' },
      { method: 'put', path: '/api/communication/preferences' },
      { method: 'get', path: '/api/communication/general' },
      { method: 'get', path: '/api/communication/meetings' },
    ];

    testEndpoints.forEach(({ method, path }) => {
      it(`should require authentication for ${method.toUpperCase()} ${path}`, async () => {
        app.use((req, res, next) => {
          req.user = undefined; // No authentication
          next();
        });

        const response = await request(app)[method as keyof typeof request](path)
          .expect(401);

        expect(response.body).toHaveProperty('code', 'AUTH_REQUIRED');
      });
    });

    it('should enforce admin-only access for populate-defaults', async () => {
      const nonAdminRoles = ['manager', 'demo_manager', 'resident', 'tenant'];
      
      for (const role of nonAdminRoles) {
        const user = testUsers.find(u => u.role === role);
        if (user) {
          app.use((req, res, next) => {
            req.user = user;
            next();
          });

          const response = await request(app)
            .post('/api/communication/preferences/populate-defaults')
            .expect(403);

          expect(response.body).toHaveProperty('code', 'INSUFFICIENT_PERMISSIONS');
        }
      }
    });

    it('should enforce creation permissions for communications and meetings', async () => {
      const restrictedRoles = ['resident', 'tenant'];
      
      for (const role of restrictedRoles) {
        const user = testUsers.find(u => u.role === role);
        if (user) {
          app.use((req, res, next) => {
            req.user = user;
            next();
          });

          // Test communication creation
          const commResponse = await request(app)
            .post('/api/communication/general')
            .send({
              organizationId: testOrgs[0].id,
              title: 'Test',
              content: 'Test',
              isUrgent: false,
              recipientRoles: ['resident'],
            })
            .expect(403);

          expect(commResponse.body).toHaveProperty('code', 'INSUFFICIENT_PERMISSIONS');

          // Test meeting creation
          const meetingResponse = await request(app)
            .post('/api/communication/meetings')
            .send({
              organizationId: testOrgs[0].id,
              title: 'Test Meeting',
              description: 'Test',
              location: 'Test',
              scheduledDate: new Date().toISOString(),
              duration: 60,
              invitedRoles: ['resident'],
            })
            .expect(403);

          expect(meetingResponse.body).toHaveProperty('code', 'INSUFFICIENT_PERMISSIONS');
        }
      }
    });
  });
